import React, {useState} from 'react';
import "./Menu.css";
import "nes.css/css/nes.min.css";

const Menu = () => {
	const [menuState, setMenuState] = useState(false);

	const openMenu = () => {
		setMenuState(true);
	}

	if (!menuState) {
    return <label>
						<a onClick={openMenu}>
							<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
							<span>Start</span>
						</a>
					</label>
	} else {
			return (
				<div class="nes-container is-rounded is-dark with-title">
  				<p class="title">OPTIONS</p>
  				<a onClick="">
					<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
					<span>Character</span>
				</a>
				<a onClick="">
					<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
						<span>Projects</span>
					</a>
					<a onClick="">
						<input type="radio" class="nes-radio is-dark" name="answer-dark" checked />
						<span>Contact</span>
					</a>
				</div>
			)
	}
}

export default Menu;
